  ('medical-tech-moex-15405', 'medical-tech', 'medical-tech-moex-099-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '某早產嬰兒其膽色素為 20 mg/dL，DAT(4+)，血清抗體篩檢為陽性。醫師備血以作交換輸血。若血 庫並無法獲得母親的檢體來作抗體鑑定及交叉試驗之用時，則下列何者為最正確的作法？', '["以嬰兒的血清作抗體鑑定，並作交叉試驗，以交叉試驗陰性的血液作為交換輸血之用", "以O型Rh (-)的血液作為交換輸血之用，不必作交叉試驗", "堅持取得母親的檢體，否則拒絕供給血液", "作嬰兒紅血球的沖出液。以嬰兒血清及沖出液作抗體鑑定及交叉試驗，兩者均合者作為輸血之用"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "342bf420f9c6", "answer_pdf_sha1": "5892de59bac6", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "104", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 71, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
